sql:
SELECT player_name, position
FROM team_roster
WHERE season_id = 0;

SELECT fan_name
FROM fans
WHERE date_joined LIKE '2023%';

SELECT COUNT(fan_id) AS enthusiast_fans
FROM fans
WHERE fan_level = 'Enthusiast';

